  'Cool Down Routine (OPTIONAL) Post-training cooldown routine to help your body recover, reduce muscle soreness, and calm your nervous system after intense sessions. Complete this after any workout to downregulate, stretch key muscles, and speed up recovery.', null::smallint
from day
on conflict (program_day_id, slug) do update set
  block_type = excluded.block_type,
  name = excluded.name,
  sort_order = excluded.sort_order,
  instructions = excluded.instructions,
  round_count = excluded.round_count;

with day as (
  select pd.id
  from public.program_days pd
  join public.programs p on p.id = pd.program_id
  where p.slug = '4-female-minimalist' and pd.slug = 'upper-b'
),
blk as (
  select pb.id, pb.program_day_id
  from public.program_blocks pb
  join day on day.id = pb.program_day_id
  where pb.slug = 'cool-down'
),
ex as (
  insert into public.program_exercises (
    program_day_id, program_block_id, slug, name, sort_order,
    prescription_mode, protocol, tempo, superset_letter,
    percentage_start, percentage_increment, work_seconds,
    target_sets, target_reps, rest_seconds, notes
  )
  select
    blk.program_day_id, blk.id,
    'banded-soulder-disloations', 'Banded Soulder Disloations', 2::smallint,
    'time_interval'::public.exercise_prescription_mode,
    'interval_progression'::public.exercise_protocol,
    null, null,
    null::smallint, null::smallint, 60::smallint,
    1::smallint, '1 min', null::smallint,
    null
  from blk
  on conflict (program_day_id, slug) do update set
    program_block_id = excluded.program_block_id,
    name = excluded.name,
    sort_order = excluded.sort_order,
    prescription_mode = excluded.prescription_mode,
    protocol = excluded.protocol,
    tempo = excluded.tempo,
    superset_letter = excluded.superset_letter,
    percentage_start = excluded.percentage_start,
    percentage_increment = excluded.percentage_increment,
    work_seconds = excluded.work_seconds,
    target_sets = excluded.target_sets,
    target_reps = excluded.target_reps,
    rest_seconds = excluded.rest_seconds,
    notes = excluded.notes
  returning id
),
ins_sets as (
  insert into public.program_exercise_sets (program_exercise_id, set_number, target_reps, rest_seconds, work_seconds, load_note)
  select ex.id, v.set_number, v.target_reps, v.rest_seconds, v.work_seconds, v.load_note
  from ex
  cross join (values (1::smallint, '1 min', null::smallint, 60::smallint, null)) as v (set_number, target_reps, rest_seconds, work_seconds, load_note)
  on conflict (program_exercise_id, set_number) do update set
    target_reps = excluded.target_reps,
    rest_seconds = excluded.rest_seconds,
    work_seconds = excluded.work_seconds,
    load_note = excluded.load_note
  returning 1
)
select 1 from ins_sets;

