  'Warm-Up & Pre-Activation', 1::smallint,
  '(Before Training) WARM UP & PRE ACTIVATION Complete 5 Minutes on any cardio equipment prior to starting your session followed by your Pre Activation Work. (It is recommended to chose cardio equipment specific to your training day. For example: Leg Day = Stationery Bike) Banded Shoulder Dislocations, Banded Pull Apart, Banded/Cable Rotator, External Rotations, Banded/Cable Rotator, Internal Rotations', null::smallint
from day
on conflict (program_day_id, slug) do update set
  block_type = excluded.block_type,
  name = excluded.name,
  sort_order = excluded.sort_order,
  instructions = excluded.instructions,
  round_count = excluded.round_count;

