    name = excluded.name,
    sort_order = excluded.sort_order,
    prescription_mode = excluded.prescription_mode,
    protocol = excluded.protocol,
    tempo = excluded.tempo,
    superset_letter = excluded.superset_letter,
    percentage_start = excluded.percentage_start,
    percentage_increment = excluded.percentage_increment,
    work_seconds = excluded.work_seconds,
    target_sets = excluded.target_sets,
    target_reps = excluded.target_reps,
    rest_seconds = excluded.rest_seconds,
    notes = excluded.notes
  returning id
),
ins_sets as (
  insert into public.program_exercise_sets (program_exercise_id, set_number, target_reps, rest_seconds, work_seconds, load_note)
  select ex.id, v.set_number, v.target_reps, v.rest_seconds, v.work_seconds, v.load_note
  from ex
  cross join (values (1::smallint, '5 min', null::smallint, 300::smallint, null)) as v (set_number, target_reps, rest_seconds, work_seconds, load_note)
  on conflict (program_exercise_id, set_number) do update set
    target_reps = excluded.target_reps,
    rest_seconds = excluded.rest_seconds,
    work_seconds = excluded.work_seconds,
    load_note = excluded.load_note
  returning 1
)
select 1 from ins_sets;